mapper.select:
/* selectMskuwcList */ SELECT CONCAT(MS.WAREKEY, MS.OWNERKY, MS.SKUMKEY) AS rowkey , MS.WAREKEY, MS.OWNERKY, MS.SKUMKEY, MS.SKUGRKY, BA.ADDSIKY , MS.SKUDESC, MS.ITEMCOD, MS.SKUWEIG , MS.SKUWIDT, MS.SKULENG, MS.SKUTHIC, MS.SUOMKEY, MS.SKUSTAT , MS.UPDTCHK, MC1.COMCDTX AS ITEMNAM, MC1.COMCDTX AS COMCDTX, MP.GRPKYNM , DATE_FORMAT(MS.CREDATE,'%Y-%m-%d') AS CREDATE , DATE_FORMAT(STR_TO_DATE(MS.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(MS.CREUSER) AS CREUSER , DATE_FORMAT(MS.LMODATE,'%Y-%m-%d') AS LMODATE , DATE_FORMAT(STR_TO_DATE(MS.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(MS.LMOUSER) AS LMOUSER FROM ${userData.schema}.MSKUWC MS INNER JOIN ${userData.schema}.MCODEM MC1 ON MC1.COMCDKY = 'ITEMCOD' AND MC1.COMCDVL = MS.ITEMCOD AND MC1.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MGRPMA MP ON MP.SKUGRKY = MS.SKUGRKY AND MP.GRUSEYN = 'Y' INNER JOIN ${userData.schema}.BADDCO BA ON MS.ADDCOKY = BA.ADDCOKY INNER JOIN ${userData.schema}.MCODEM MC2 ON MC2.COMCDKY = 'ADDSIKY' AND MC2.COMCDVL = BA.ADDSIKY AND MC2.COUSEYN = 'Y'
AND MS.WAREKEY = #{params.warekey}
AND MS.OWNERKY LIKE CONCAT('%', UPPER(#{params.ownerky}), '%')
AND MS.SKUGRKY = #{params.skugrky}
AND MC2.COMCDVL = #{params.addsiky}
AND UPPER(MS.SKUMKEY) LIKE CONCAT('%', UPPER(#{params.skumkey}), '%')
AND UPPER(MS.SKUDESC) LIKE CONCAT('%', UPPER(#{params.skudesc}), '%')
AND MS.ITEMCOD = #{params.itemcod}
AND MS.SKUSTAT = #{params.skustat}
AND MS.SKUMKEY IN
#{item}
ORDER BY MS.SKUDESC, MS.SKUMKEY, MS.OWNERKY

mapper.insert:
		/* insertMskuwc */
		INSERT INTO ${userData.schema}.MSKUWC (
	        WAREKEY, OWNERKY, SKUMKEY, SKUGRKY, ADDCOKY
	        , SKUDESC, ITEMCOD, SKUWEIG, SKUWIDT, SKULENG
	        , SKUTHIC, SUOMKEY, SKUSTAT, CREDATE, CRETIME
	        , CREUSER, LMODATE, LMOTIME, LMOUSER
	    )
	    VALUES (
	        #{addData.warekey}, IFNULL(#{addData.ownerky}, ''), #{addData.skumkey}
	        ,(
	        	SELECT MG.SKUGRKY
				FROM ${userData.schema}.MGRPMA MG
				WHERE ((MG.MINLENG = 0 OR MG.MINLENG <= #{addData.skuleng}) AND (MG.MAXLENG = 0 OR #{addData.skuleng} < MG.MAXLENG))
				AND((MG.MINWIDT = 0 OR MG.MINWIDT <= #{addData.skuwidt}) AND (MG.MAXWIDT = 0 OR #{addData.skuwidt} < MG.MAXWIDT))
				AND MG.GRUSEYN = 'Y'
        	)
        	,(
				 CASE
				 WHEN (SELECT CDCATE3 FROM ${userData.schema}.MCODEM WHERE COMCDKY = 'ITEMCOD' AND COMCDVL = #{addData.itemcod}) = 'PLATE'
				 THEN (SELECT BA.ADDCOKY
					     FROM ${userData.schema}.BADDCO BA
					    WHERE ((BA.MINLENG = 0 OR BA.MINLENG <= #{addData.skuleng}) AND (BA.MAXLENG = 0 OR #{addData.skuleng} < BA.MAXLENG))
					      AND ((BA.MINWIDT = 0 OR BA.MINWIDT <= #{addData.skuwidt}) AND (BA.MAXWIDT = 0 OR #{addData.skuwidt} < BA.MAXWIDT))
					      AND BA.SYSCDYN = 'N'
					  )
	    	 	 ELSE (SELECT BAD.ADDCOKY
	    	 	 		 FROM ${userData.schema}.BADDCO BAD
	    	 	 		WHERE BAD.SYSCDYN = 'Y'
			    	  )
				  END
			)
        	, #{addData.skudesc}, #{addData.itemcod}, #{addData.skuweig}, #{addData.skuwidt}
        	, #{addData.skuleng}, #{addData.skuthic}, #{addData.suomkey}, #{addData.skustat}
        	, to_char(NOW(), 'YYYYMMDD'), to_char(NOW(), 'HH24MISS'), #{userData.useract}
        	, to_char(NOW(), 'YYYYMMDD'), to_char(NOW(), 'HH24MISS'), #{userData.useract}
	    )

mapper.update:
	/* updateMskuwc */
	UPDATE ${userData.schema}.MSKUWC SET
		OWNERKY = #{updateData.ownerky}
		, SKUGRKY = (
			SELECT MG.SKUGRKY
			FROM ${userData.schema}.MGRPMA MG
			WHERE ((MG.MINLENG = 0 OR MG.MINLENG <= #{updateData.skuleng}) AND (MG.MAXLENG = 0 OR #{updateData.skuleng} < MG.MAXLENG))
			AND((MG.MINWIDT = 0 OR MG.MINWIDT <= #{updateData.skuwidt}) AND (MG.MAXWIDT = 0 OR #{updateData.skuwidt} < MG.MAXWIDT))
			AND MG.GRUSEYN = 'Y'
		)
		, ADDCOKY = (
			 CASE
			 WHEN (SELECT CDCATE3 FROM ${userData.schema}.MCODEM WHERE COMCDKY = 'ITEMCOD' AND COMCDVL = #{updateData.itemcod}) = 'PLATE'
			 THEN (SELECT BA.ADDCOKY
				     FROM ${userData.schema}.BADDCO BA
				    WHERE ((BA.MINLENG = 0 OR BA.MINLENG <= #{updateData.skuleng}) AND (BA.MAXLENG = 0 OR #{updateData.skuleng} < BA.MAXLENG))
				      AND ((BA.MINWIDT = 0 OR BA.MINWIDT <= #{updateData.skuwidt}) AND (BA.MAXWIDT = 0 OR #{updateData.skuwidt} < BA.MAXWIDT))
				      AND BA.SYSCDYN = 'N'
				  )
    	 	 ELSE (SELECT BAD.ADDCOKY
    	 	 		 FROM ${userData.schema}.BADDCO BAD
    	 	 		WHERE BAD.SYSCDYN = 'Y'
		    	  )
			  END
		)
		, SKUDESC = #{updateData.skudesc}
		, ITEMCOD = #{updateData.itemcod}
		, SKUWEIG = #{updateData.skuweig}
		, SKUWIDT = #{updateData.skuwidt}
		, SKULENG = #{updateData.skuleng}
		, SKUTHIC = #{updateData.skuthic}
		, SUOMKEY = #{updateData.suomkey}
		, SKUSTAT = #{updateData.skustat}
		, LMODATE = to_char(NOW() ,'YYYYMMDD')
		, LMOTIME = to_char(NOW() ,'hh24miss')
		, LMOUSER = #{userData.useract}
		, UPDTCHK = #{updateData.updtchk} + 1
	WHERE UPDTCHK = #{updateData.updtchk}


			AND WAREKEY = #{updateData.oldWarekey}


			AND WAREKEY = #{updateData.warekey}




			AND OWNERKY = #{updateData.oldOwnerky}


			AND OWNERKY = #{updateData.ownerky}




			AND SKUMKEY = #{updateData.oldSkumkey}


			AND SKUMKEY = #{updateData.skumkey}




			AND SKUGRKY = #{updateData.oldSkugrky}


			AND SKUGRKY = #{updateData.skugrky}

mapper.select:
/* selectMskuwcSelectBox */
SELECT SKUMKEY AS combovl, SKUDESC AS combonm
FROM ${userData.schema}.MSKUWC
WHERE SKUSTAT = '00' 

	AND WAREKEY = #{params.warekey}


	AND OWNERKY = #{params.ownerky}


	AND SKUGRKY = #{params.skugrky}


	AND SKUMKEY = #{params.skumkey}

GROUP BY SKUDESC, SKUMKEY
ORDER BY SKUDESC, SKUMKEY

/* selectMgrpmaList */ SELECT SKUGRKY AS rowkey , SKUGRKY, GRPKYNM, MINLENG, MINWIDT, MAXLENG , MAXWIDT, VHCTYPE, SKUGROR, GRUSEYN, UPDTCHK , SZGUBUN , DATE_FORMAT(CREDATE,'%Y-%m-%d') AS CREDATE , DATE_FORMAT(STR_TO_DATE(CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(CREUSER) AS CREUSER , DATE_FORMAT(LMODATE,'%Y-%m-%d') AS LMODATE , DATE_FORMAT(STR_TO_DATE(LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(LMOUSER) AS LMOUSER FROM ${userData.schema}.MGRPMA
AND SKUGRKY LIKE CONCAT('%', UPPER(#{params.skugrky}), '%')
AND GRPKYNM LIKE CONCAT('%', UPPER(#{params.grpkynm}), '%')
AND VHCTYPE = #{params.vhctype}
AND GRUSEYN = #{params.gruseyn}
ORDER BY SKUGROR, GRPKYNM, SKUGRKY

