/* selectMgrpmaSelectBox */ SELECT SKUGRKY AS combovl, GRPKYNM AS combonm FROM ${userData.schema}.MGRPMA WHERE GRUSEYN = 'Y'
AND SKUGRKY = #{params.skugrky}
GROUP BY SKUGRKY, GRPKYNM ORDER BY SKUGROR, SZGUBUN, GRPKYNM, SKUGRKY

/* selectMuommaSelectBox */ SELECT UOMEKEY AS combovl, UOMENAM AS combonm FROM ${userData.schema}.MUOMMA WHERE UOUSEYN = 'Y'
AND UOMEKEY = #{params.uomekey}
GROUP BY UOMENAM, UOMEKEY ORDER BY UOMENAM, UOMEKEY
